document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll(".features-section .feature").forEach(e=>{var r=e.querySelector("h3");if(r){r=r.querySelector("a");if(r){let t=r.getAttribute("href"),n=r.getAttribute("target")||"_self";e.addEventListener("click",function(e){e.target.closest("a")||("_blank"===n?window.open(t,"_blank"):window.location.href=t)}),e.classList.add("clickable-feature")}}})});